      "content": "const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');
const { validateMemberPayload } = require('../../lib/validation');

const projects = {};

module.exports = {
  addMember(projectId, member) {
    if (!projects[projectId]) {
      projects[projectId] = { id: projectId, members: [] };
    }
    if (!validateMemberPayload(member)) {
      return null;
    }
    const existingMember = projects[projectId].members.find(m => m.userId === member.userId);
    if (existingMember) {
      return null;
    }
    projects[projectId].members.push({ id: randomUUID(), ...member });
    return projects[projectId].members;
  },
  getMembers(projectId) {
    return projects[projectId] ? projects[projectId].members : null;
  }
};
