      "content": "const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');
const { validateTaskStatus } = require('../../lib/validation');

const projects = {};

module.exports = {
  addTask(projectId, task) {
    if (!projects[projectId]) {
      projects[projectId] = { id: projectId, tasks: [] };
    }
    task.status = 'todo';
    projects[projectId].tasks.push({ id: randomUUID(), ...task });
    return projects[projectId].tasks;
  },
  updateTaskStatus(projectId, taskId, status) {
    if (!validateTaskStatus(status)) {
      return null;
    }
    const project = projects[projectId];
    if (!project) {
      return null;
    }
    const task = project.tasks.find(t => t.id === taskId);
    if (!task) {
      return null;
    }
    task.status = status;
    return project.tasks;
  },
  getTasks(projectId, status) {
    const project = projects[projectId];
    if (!project) {
      return null;
    }
    if (status) {
      return project.tasks.filter(t => t.status === status);
    }
    return project.tasks;
  }
};
